<template>
    <div class="modify">
        <div class="nav">
            <van-icon name="arrow-left" @click="$router.back()" />
            <p>账户管理</p>
            <van-icon name="service-o" />
        </div>
        <div class="content">
       <p>
           <span>昵称</span>
           <span>{{user.nickname}}</span>
       </p>
       <p>
           <span>余额</span>
           <span>{{user.now_money}}</span>
       </p>
       <p>
           <span>ID</span>
           <span>{{user.uid}}</span>
       </p>
       <p>
           <span>电话</span>
           <span>{{user.phone}}</span>
       </p>
       <router-link tag="p" to="/modifycode">
           <span>修改密码</span>
           <van-icon  class="arrow" name="arrow" />
       </router-link>
        </div>
        <div class="btn">
            <p @click="saveModify">保存</p>
            <p @click="Out">退出</p>
        </div>
    </div>
</template>
<script>
import {mapGetters,mapMutations} from 'vuex'
export default {
    data(){
    return{
    user:''
    }
  },
  created(){
    this.axios.get('/api/user').then(d=>{
      this.user = d.data.data;
    })
  },
    computed:{
    ...mapGetters(['userMsg'])
  },

  methods:{
      saveModify(){
       this.axios.post('/api/user/edit',{
        avatar: "http://kaifa.crmeb.net/uploads/attach/2019/08/20190807/723adbdd4e49a0f9394dfc700ab5dba3.png",
        nickname: this.user.nickname
       }).then(da=>{
           this.axios.get('/api/userinfo').then(data=>{
               this.user = data.data.data;
           })
        
         console.log(da);
       }),
         this.$toast({
            message: "保存成功",
            icon: "passed",
            onClose: () => {
              this.$router.back();
            },
          });
      },
       Out(){
      this.loginOut();
       this.$toast({
        message:"退出成功",
        icon:"passed",
        onClose:()=>{
          this.$router.push('/login');
        }
      })
    },
    ...mapMutations(['saveToken','saveLoginInfo','loginOut']),

  }
}
</script>
<style lang="less" scoped>
.modify{
    width:100%;
    background-color: whitesmoke;
    height: 100vh;
    font-size: 16px;
    .nav{
        height: 50px;
        background-color: #fff;
        display: flex;
        justify-content: space-between;
        padding: 0 10px;
        align-items: center;
        p{
            height: 100%;
            margin: 0;
            line-height:50px;
        }
    }
    .content{
        background-color: #fff;
          margin-top: 15px;
        p{
          margin: 0;
          height: 50px;
          color: #666;
          display: flex;
          justify-content: space-between;
          padding: 0 10px;
          align-items: center;
          border-bottom: 1px solid whitesmoke;
        }
    }
    .btn{
       p{
           width: 100%;
           height: 50px;
           line-height: 50px;
           background-color: #fff;
           text-align: center;
           &:nth-child(1){
               color: tomato;
           }
       }
    }
}
</style>